var pallet = {};
var items = [];
var currentType = 'freetext';
var selectedAsset = null;
var selectedPart = null;
function fmt(d) {
  if (!d) return '—';
  return new Date(d).toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function wasteTypeLabel(t) {
  var map = {
    mixed_electrical: 'Mixed Electrical',
    hazardous: 'Hazardous',
    battery: 'Battery',
    other: 'Other'
  };
  return map[t] || t || '—';
}
function statusBadge(s) {
  var cls = {
    open: 'badge-open',
    closed: 'badge-closed',
    collected: 'badge-collected'
  };
  return 'badge ' + (cls[s] || 'badge-open');
}
function renderHeader(p) {
  if (!p) return;
  var wi = document.getElementById('hdr_waste_id');
  var ws = document.getElementById('hdr_status');
  var wt = document.getElementById('hdr_waste_type');
  var mv = document.getElementById('meta_vendor');
  var mw = document.getElementById('meta_weight');
  var mc = document.getElementById('meta_created');
  var ml = document.getElementById('meta_collection');
  if (wi) wi.textContent = p.waste_id || '—';
  if (ws) {
    ws.textContent = p.status || 'open';
    ws.className = statusBadge(p.status);
  }
  if (wt) wt.textContent = wasteTypeLabel(p.waste_type);
  if (mv) mv.textContent = p.vendor_name || 'No vendor assigned';
  if (mw) mw.textContent = p.weight_kg ? p.weight_kg + ' kg' : '—';
  if (mc) mc.textContent = fmt(p.created_date);
  if (ml) ml.textContent = fmt(p.collection_date);
}
function renderItems(its) {
  var tbody = document.getElementById('items_body');
  if (!tbody) return;
  if (!its.length) {
    tbody.innerHTML = '<tr><td colspan="7" class="empty">No items on this pallet yet</td></tr>';
    return;
  }
  tbody.innerHTML = its.map(function (it) {
    var typeClass = {
      asset: 'type-asset',
      part: 'type-part',
      freetext: 'type-freetext'
    };
    var ref = it.asset_ref ? '<span style="font-family:monospace;font-size:11px;background:#EEF2FF;color:#3730A3;padding:1px 6px;border-radius:3px">' + it.asset_ref + '</span>' : it.part_ref ? '<span style="font-family:monospace;font-size:11px;background:#E1F5EE;color:#085041;padding:1px 6px;border-radius:3px">' + it.part_ref + '</span>' : '—';
    var desc = it.description || [it.make_name, it.model_name].filter(Boolean).join(' ') || it.part_type || '' || '—';
    return '<tr>' + '<td><span class="item-type ' + (typeClass[it.item_type] || 'type-freetext') + '">' + it.item_type + '</span></td>' + '<td>' + ref + '</td>' + '<td>' + desc + '</td>' + '<td>' + (it.quantity || 1) + '</td>' + '<td>' + (it.added_by || '—') + '</td>' + '<td>' + fmt(it.added_date) + '</td>' + '<td><button class="btn-sm btn-danger" onclick="window.deleteItem(' + it.item_id + ')">Remove</button></td>' + '</tr>';
  }).join('');
}
function render(model) {
  pallet = model.pallet || {};
  items = model.items || [];
  renderHeader(pallet);
  renderItems(items);
}
window.goBack = function () {
  appsmith.triggerEvent('onGoBack');
};
window.closePallet = function () {
  appsmith.updateModel({
    close_pallet: true
  });
  appsmith.triggerEvent('onClosePallet');
};
window.openAddForm = function () {
  selectedAsset = null;
  selectedPart = null;
  document.getElementById('f_description').value = '';
  document.getElementById('f_quantity').value = '1';
  document.getElementById('f_notes').value = '';
  document.getElementById('f_asset_search').value = '';
  document.getElementById('f_part_search').value = '';
  document.getElementById('selected_asset').style.display = 'none';
  document.getElementById('selected_part').style.display = 'none';
  document.getElementById('asset_results').style.display = 'none';
  document.getElementById('part_results').style.display = 'none';
  window.setType('freetext');
  document.getElementById('add_form').classList.add('open');
};
window.closeAddForm = function () {
  document.getElementById('add_form').classList.remove('open');
};
window.setType = function (type) {
  currentType = type;
  ['freetext', 'asset', 'part'].forEach(function (t) {
    document.getElementById(t + '_fields').style.display = t === type ? 'block' : 'none';
  });
  document.querySelectorAll('.type-tab').forEach(function (btn, i) {
    btn.className = 'type-tab' + (['freetext', 'asset', 'part'][i] === type ? ' active' : '');
  });
};
window.searchAssets = function () {
  var q = document.getElementById('f_asset_search').value;
  if (q.length < 2) {
    document.getElementById('asset_results').style.display = 'none';
    return;
  }
  appsmith.updateModel({
    search_query: q,
    search_type: 'asset'
  });
  appsmith.triggerEvent('onSearchAssets');
};
window.searchParts = function () {
  var q = document.getElementById('f_part_search').value;
  if (q.length < 2) {
    document.getElementById('part_results').style.display = 'none';
    return;
  }
  appsmith.updateModel({
    search_query: q,
    search_type: 'part'
  });
  appsmith.triggerEvent('onSearchParts');
};
window.selectAsset = function (idx) {
  var results = appsmith.model.asset_results || [];
  selectedAsset = results[idx];
  if (!selectedAsset) return;
  var el = document.getElementById('selected_asset');
  el.textContent = selectedAsset.asset_ref + ' — ' + [selectedAsset.make_name, selectedAsset.model_name].filter(Boolean).join(' ');
  el.style.display = 'block';
  document.getElementById('asset_results').style.display = 'none';
};
window.selectPart = function (idx) {
  var results = appsmith.model.part_results || [];
  selectedPart = results[idx];
  if (!selectedPart) return;
  var el = document.getElementById('selected_part');
  el.textContent = selectedPart.part_ref + ' — ' + (selectedPart.part_type || '') + (selectedPart.condition_grade ? ' Grade ' + selectedPart.condition_grade : '');
  el.style.display = 'block';
  document.getElementById('part_results').style.display = 'none';
};
window.deleteItem = function (itemId) {
  appsmith.updateModel({
    delete_item_id: itemId
  });
  appsmith.triggerEvent('onDeleteItem');
};
window.saveItem = function () {
  var data = {
    item_type: currentType,
    item_asset_id: selectedAsset ? selectedAsset.asset_id : null,
    item_part_id: selectedPart ? selectedPart.id : null,
    item_description: document.getElementById('f_description').value,
    item_quantity: parseInt(document.getElementById('f_quantity').value) || 1,
    item_notes: document.getElementById('f_notes').value
  };
  if (currentType === 'asset' && !selectedAsset) {
    alert('Please select an asset');
    return;
  }
  if (currentType === 'part' && !selectedPart) {
    alert('Please select a part');
    return;
  }
  appsmith.updateModel(data);
  appsmith.triggerEvent('onSaveItem');
  window.closeAddForm();
};
appsmith.onModelChange(function (model) {
  var ar = model.asset_results;
  var pr = model.part_results;
  if (ar !== undefined) {
    var el = document.getElementById('asset_results');
    if (ar && ar.length) {
      el.style.display = 'block';
      el.innerHTML = ar.map(function (r, i) {
        return '<div class="search-result-row" onclick="window.selectAsset(' + i + ')">' + '<span><span class="result-ref">' + r.asset_ref + '</span>' + [r.make_name, r.model_name].filter(Boolean).join(' ') + '</span>' + '<span style="font-size:11px;color:#9ca3af">' + (r.serial_number || '') + '</span>' + '</div>';
      }).join('');
    } else {
      el.style.display = 'none';
    }
  }
  if (pr !== undefined) {
    var el2 = document.getElementById('part_results');
    if (pr && pr.length) {
      el2.style.display = 'block';
      el2.innerHTML = pr.map(function (r, i) {
        return '<div class="search-result-row" onclick="window.selectPart(' + i + ')">' + '<span><span class="result-ref">' + r.part_ref + '</span>' + (r.part_type || '') + '</span>' + '<span style="font-size:11px;color:#9ca3af">Grade ' + (r.condition_grade || '—') + '</span>' + '</div>';
      }).join('');
    } else {
      el2.style.display = 'none';
    }
  }
  render(model);
});
appsmith.onReady(function () {
  render(appsmith.model);
});

